const ticker = $('Split Watchlist into Items').item.json;
const quote = $('Alpha Vantage - Fetch Quote & Fundamentals').item.json['Global Quote'] || {};
const overview = $('Alpha Vantage - Fetch Company Overview').item.json || {};
const newsItems = $('NewsAPI - Fetch Company News').item.json.articles || [];
const articleContent = $input.item.json || '';

// Parse price data
const currentPrice = parseFloat(quote['05. price'] || 0);
const prevClose = parseFloat(quote['08. previous close'] || 0);
const priceChange = parseFloat(quote['09. change'] || 0);
const priceChangePct = parseFloat(quote['10. change percent']?.replace('%', '') || 0);
const volume = parseInt(quote['06. volume'] || 0);
const avgVolume = parseInt(quote['07. latest trading day'] || 0);
const high52 = parseFloat(quote['03. high'] || 0);
const low52 = parseFloat(quote['04. low'] || 0);

// Fundamental data from overview
const peRatio = parseFloat(overview.PERatio || 0);
const eps = parseFloat(overview.EPS || 0);
const pbRatio = parseFloat(overview.PriceToBookRatio || 0);
const dividendYield = parseFloat(overview.DividendYield || 0);
const marketCap = overview.MarketCapitalization || '0';
const sector = overview.Sector || ticker.Sector || 'Unknown';
const beta = parseFloat(overview.Beta || 1);
const analystTarget = parseFloat(overview.AnalystTargetPrice || 0);
const forwardPE = parseFloat(overview.ForwardPE || 0);
const profitMargin = parseFloat(overview.ProfitMargin || 0);
const revenueGrowthYoY = parseFloat(overview.QuarterlyRevenueGrowthYOY || 0);
const earningsGrowthYoY = parseFloat(overview.QuarterlyEarningsGrowthYOY || 0);

// Price vs analyst target
const upsidePotential = analystTarget > 0 ? ((analystTarget - currentPrice) / currentPrice * 100).toFixed(1) : 'N/A';

// Momentum signal (proximity to 52-week high)
const from52WeekHigh = high52 > 0 ? ((currentPrice - high52) / high52 * 100).toFixed(1) : '0';
const from52WeekLow = low52 > 0 ? ((currentPrice - low52) / low52 * 100).toFixed(1) : '0';

// Simple technical signal
let technicalSignal = 'NEUTRAL';
if (priceChangePct > 2 && parseFloat(from52WeekHigh) > -10) technicalSignal = 'BULLISH';
else if (priceChangePct < -2 && parseFloat(from52WeekHigh) < -20) technicalSignal = 'BEARISH';

// Value signal
let valuationSignal = 'FAIR';
if (peRatio > 0 && peRatio < 15 && profitMargin > 0.1) valuationSignal = 'UNDERVALUED';
else if (peRatio > 35 || (peRatio > 25 && profitMargin < 0.05)) valuationSignal = 'OVERVALUED';

// News headlines
const headlines = newsItems.slice(0, 3).map(a => ({ title: a.title, source: a.source?.name, url: a.url, publishedAt: a.publishedAt }));

return {
  json: {
    ticker: ticker.Ticker,
    companyName: ticker.CompanyName || overview.Name || ticker.Ticker,
    sector,
    currentPrice,
    prevClose,
    priceChange,
    priceChangePct,
    volume,
    high52,
    low52,
    from52WeekHigh,
    from52WeekLow,
    peRatio,
    forwardPE,
    eps,
    pbRatio,
    dividendYield,
    beta,
    analystTarget,
    upsidePotential,
    profitMargin: (profitMargin * 100).toFixed(1),
    revenueGrowthYoY: (revenueGrowthYoY * 100).toFixed(1),
    earningsGrowthYoY: (earningsGrowthYoY * 100).toFixed(1),
    marketCap,
    technicalSignal,
    valuationSignal,
    headlines,
    articleContent: typeof articleContent === 'string' ? articleContent.substring(0, 3000) : JSON.stringify(articleContent).substring(0, 3000),
    analysedAt: new Date().toISOString()
  }
};

const raw = $input.item.json.content?.[0]?.text || '{}';
const data = $('Merge & Calculate Technical Signals').item.json;
let thesis;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  thesis = match ? JSON.parse(match[0]) : {};
} catch(e) {
  thesis = { recommendation: 'HOLD', confidenceLevel: 'LOW', investmentThesis: 'Analysis failed — manual review required.', bullCase: '', bearCase: '', newsSentiment: 'NEUTRAL', newsSentimentReason: '', keyRisks: [], keyTriggers: [], priceTarget12m: null, stopLossLevel: null, oneLineSummary: 'Manual review required' };
}

const recEmoji = { 'STRONG BUY': '🟢🟢', 'BUY': '🟢', 'HOLD': '🟡', 'SELL': '🔴', 'STRONG SELL': '🔴🔴' };

return {
  json: {
    ...data,
    recommendation: thesis.recommendation || 'HOLD',
    recEmoji: recEmoji[thesis.recommendation] || '🟡',
    confidenceLevel: thesis.confidenceLevel || 'LOW',
    investmentThesis: thesis.investmentThesis || '',
    bullCase: thesis.bullCase || '',
    bearCase: thesis.bearCase || '',
    newsSentiment: thesis.newsSentiment || 'NEUTRAL',
    newsSentimentReason: thesis.newsSentimentReason || '',
    keyRisks: thesis.keyRisks || [],
    keyTriggers: thesis.keyTriggers || [],
    priceTarget12m: thesis.priceTarget12m || null,
    stopLossLevel: thesis.stopLossLevel || null,
    oneLineSummary: thesis.oneLineSummary || ''
  }
};

const raw = $input.item.json.content?.[0]?.text || '{}';
const allData = $('Aggregate All Analyses').item.json.data || [];
let briefing;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  briefing = match ? JSON.parse(match[0]) : {};
} catch(e) {
  briefing = { briefingDate: new Date().toLocaleDateString(), marketOutlook: 'MIXED', executiveOverview: 'Briefing parse error — please review individual analyses.', topPick: { ticker: '—', reason: '' }, avoidToday: { ticker: '—', reason: '' }, themeOfTheDay: 'Manual review needed', stockSummaries: [], keyRisksToday: [], actionItems: [], closingNote: '' };
}

const outlookEmoji = { 'RISK-ON': ':green_circle:', 'RISK-OFF': ':red_circle:', 'MIXED': ':yellow_circle:' };

// Build full Markdown report
const report = `# 📊 Daily Investment Briefing
${briefing.briefingDate}

---

## Market Outlook: ${outlookEmoji[briefing.marketOutlook] || ''} ${briefing.marketOutlook}

${briefing.executiveOverview}

---

## 🏆 Today's Top Pick: ${briefing.topPick?.ticker}

${briefing.topPick?.reason}

## ⚠️ Avoid Today: ${briefing.avoidToday?.ticker}

${briefing.avoidToday?.reason}

---

## 📰 Theme of the Day

${briefing.themeOfTheDay}

---

## Stock Summaries

${ (briefing.stockSummaries || []).map(s => `### ${s.ticker} — ${s.recommendation} (${s.confidence} confidence)
${s.headline}`).join('

') }

---

## Key Risks to Monitor

${ (briefing.keyRisksToday || []).map((r,i) => `${i+1}. ${r}`).join('
') }

---

## Today's Action Items

${ (briefing.actionItems || []).map(a => `- ${a}`).join('
') }

---

> *${briefing.closingNote}*

---

*DISCLAIMER: This briefing is generated by AI and is for informational purposes only. It does not constitute financial advice. Past performance is not indicative of future results. All investment decisions should be made in consultation with a licensed financial adviser.*`;

return {
  json: {
    ...briefing,
    outlookEmoji: outlookEmoji[briefing.marketOutlook] || ':yellow_circle:',
    reportContent: report,
    stockCount: allData.length,
    generatedAt: new Date().toISOString()
  }
};
